// Bicep: zone-redundant AKS + zonal managed disk
param location string = resourceGroup().location

// Zone-redundant AKS cluster
resource aks 'Microsoft.ContainerService/managedClusters@2023-05-01' = {
  name: 'prod-cluster'
  location: location
  identity: { type: 'SystemAssigned' }
  properties: {
    dnsPrefix: 'prod-cluster'
    agentPoolProfiles: [
      {
        name: 'system'
        count: 3
        vmSize: 'Standard_D4s_v5'
        availabilityZones: ['1', '2', '3']    // Spread across AZs
        mode: 'System'
        osType: 'Linux'
      }
    ]
  }
}

// Zonal managed disk (Zone 1 only)
resource disk 'Microsoft.Compute/disks@2023-04-02' = {
  name: 'data-disk-zone1'
  location: location
  zones: ['1']                                // Pin to Zone 1
  sku: { name: 'Premium_LRS' }
  properties: {
    creationData: { createOption: 'Empty' }
    diskSizeGB: 256
  }
}

# Azure Chaos Studio: create a zone-level shutdown experiment
# (requires Chaos Studio enabled on the subscription)

# 1. Enable Chaos targets on the resource group's VMs
az rest --method PUT \
  --uri "https://management.azure.com/subscriptions/<sub>/resourceGroups/prod-rg/providers/Microsoft.Chaos/targets/Microsoft-VirtualMachine?api-version=2023-04-15-preview" \
  --body '{"properties": {}}'

# 2. Create a chaos experiment that shuts down Zone 1 VMs for 5 minutes
az rest --method PUT \
  --uri "https://management.azure.com/subscriptions/<sub>/resourceGroups/prod-rg/providers/Microsoft.Chaos/experiments/zone1-shutdown?api-version=2023-04-15-preview" \
  --body '{
    "location": "eastus",
    "properties": {
      "steps": [{
        "name": "Zone 1 shutdown",
        "branches": [{
          "name": "branch1",
          "actions": [{
            "type": "discrete",
            "name": "urn:csci:microsoft:virtualMachine:shutdown/1.0",
            "parameters": [{"key": "abruptShutdown", "value": "false"}],
            "duration": "PT5M",
            "selectorId": "zone1-selector"
          }]
        }]
      }],
      "selectors": [{
        "type": "List",
        "id": "zone1-selector",
        "targets": [
          {"type": "ChaosTarget", "id": "/subscriptions/<sub>/resourceGroups/prod-rg/providers/Microsoft.Compute/virtualMachines/app-vm-zone1/providers/Microsoft.Chaos/targets/Microsoft-VirtualMachine"}
        ]
      }]
    }
  }'
